//all the sprite stuff
var back = createSprite(200, 200);
back.setAnimation("backround 1");
back.height = 400;
back.width = 400;


var balloon = createSprite(200, 370);
balloon.setAnimation("balloon");
balloon.height = 60;
balloon.width = 30;
var dart = createSprite(300, 0);
dart.setAnimation("dart");
dart.velocityY = 15;
dart.scale = 1.5;
var dart2 = createSprite(100, 0);
dart2.setAnimation("dart2");
dart2.velocityY = 13;
dart2.scale = 1.5;
var dart3 = createSprite(400, 0);
dart3.setAnimation("dart3");
dart3.velocityY = 13;
var score = 0;
// Create your sprites here
function draw() {
  // draw background
  if (keyDown("a")) {
    balloon.velocityX = -13;
  }
  if (keyDown("d")) {
    balloon.velocityX = 13;
  }
  if (keyDown("left")) {
    balloon.velocityX = -13;
  }
  if (keyDown("right")) {
    balloon.velocityX = 13;
  }
  if (balloon.x > 400) {
    balloon.velocityX = -15;
  }
  if (balloon.x < 0) {
    balloon.velocityX = 15;
  }
  if (dart.y > 400) {
    dart.x = randomNumber(1, 400);
    dart.y = randomNumber(1, -700);
  }
  if (dart2.y > 400) {
    dart2.x = randomNumber(1, 400);
    dart2.y = randomNumber(1, -700);
  }
  if (dart3.y > 400) {
    dart3.x = randomNumber(1, 400);
    dart3.y = randomNumber(1, -700);
  }
  if (score == 400) {
    back.setAnimation("backround2");
    dart.velocityY = 18;
    dart2.velocityY = 16;
    dart3.velocityY = 16;
  }
  if (score == 800) {
    back.setAnimation("backround3");
    dart.velocityY = 21;
    dart2.velocityY = 19;
    dart3.velocityY = 19;
  }
  if (score == 1100) {
    back.setAnimation("win");
    balloon.visible = false;
    dart2.visible = false;
    dart.visible = false;
    dart3.visible = false;
    dart.velocityY = 0;
    dart2.velocityY = 0;
    dart3.velocityY = 0;
  }
  if (balloon.visible) {
    score = score + 1;
  }
  if (balloon.isTouching(dart)) {
    back.setAnimation("lose");
    balloon.visible = false;
    dart.visible = false;
    dart2.visible = false;
    dart3.visible = false;
  }
  if (balloon.isTouching(dart2)) {
    back.setAnimation("lose");
    balloon.visible = false;
    dart.visible = false;
    dart2.visible = false;
    dart3.visible = false;
  }
  if (balloon.isTouching(dart3)) {
    back.setAnimation("lose");
    balloon.visible = false;
    dart.visible = false;
    dart2.visible = false;
    dart3.visible = false;
  }
  if (keyWentDown("space")) {
    score = 0;
    balloon.x = 200;
    balloon.velocityX = 0;
    dart.y = 0;
    dart2.y = 0;
    dart3.y = 0;
    back.setAnimation("backround 1");
    dart.velocityY = 15;
    dart2.velocityY = 13;
    dart3.velocityY = 13;
    dart.visible = true;
    dart2.visible = true;
    dart3.visible = true;
    balloon.visible = true;
  }
  drawSprites();
}



